    /// Search emoji by prefix match on name and keywords, with contains fallback.
    public static func search(_ query: String, limit: Int = 8) -> [Entry] {
        guard !query.isEmpty else { return [] }
        let q = query.lowercased()
        // Prefix matches first (higher relevance)
        var results: [Entry] = []
        var containsResults: [Entry] = []
        for entry in all {
            if entry.name.hasPrefix(q) {
                results.append(entry)
            } else if entry.name.contains(q) || entry.keywords.contains(where: { $0.hasPrefix(q) }) {
                containsResults.append(entry)
            }
            if results.count + containsResults.count >= limit * 2 { break }
        }
        if results.count < limit {
            results.append(contentsOf: containsResults.prefix(limit - results.count))
        }
        return Array(results.prefix(limit))
    }
